import json, anthropic

client = anthropic.Anthropic()

# --- Tool implementations ---
def search_documents(query: str, max_results: int = 5) -> list:
    return db.search(query, limit=max_results)

def create_ticket(title: str, description: str, priority: str) -> dict:
    ticket = ticketing.create(title=title, body=description, priority=priority)
    return {"id": ticket.id, "url": ticket.url}

# --- Registry ---
TOOL_REGISTRY = {
    "search_documents": search_documents,
    "create_ticket":    create_ticket,
}

def execute_tool(block) -> dict:
    """Route a tool_use block to its implementation and return a tool_result."""
    fn = TOOL_REGISTRY.get(block.name)
    if fn is None:
        return {
            "type": "tool_result", "tool_use_id": block.id,
            "content": f"Unknown tool: {block.name!r}", "is_error": True
        }
    try:
        result = fn(**block.input)
        return {
            "type": "tool_result", "tool_use_id": block.id,
            "content": json.dumps(result)
        }
    except TypeError as e:
        # Wrong argument names or types — schema mismatch
        return {
            "type": "tool_result", "tool_use_id": block.id,
            "content": f"Argument error: {e}", "is_error": True
        }
    except Exception as e:
        return {
            "type": "tool_result", "tool_use_id": block.id,
            "content": str(e), "is_error": True
        }

import asyncio, json, anthropic

# Async implementations for I/O-bound tools
async def search_documents_async(query: str, max_results: int = 5) -> list:
    async with aiohttp.ClientSession() as session:
        async with session.get(SEARCH_URL, params={"q": query, "n": max_results}) as r:
            return await r.json()

async def get_stock_price_async(ticker: str) -> dict:
    async with aiohttp.ClientSession() as session:
        async with session.get(f"{PRICE_API}/{ticker}") as r:
            return await r.json()

ASYNC_REGISTRY = {
    "search_documents": search_documents_async,
    "get_stock_price":  get_stock_price_async,
}

async def execute_all_tools(tool_use_blocks: list) -> list:
    """Execute all tool_use blocks concurrently."""
    tasks = []
    for block in tool_use_blocks:
        fn = ASYNC_REGISTRY.get(block.name)
        if fn:
            tasks.append((block, fn(**block.input)))
        else:
            tasks.append((block, None))

    results = []
    for block, coro in tasks:
        if coro is None:
            results.append({
                "type": "tool_result", "tool_use_id": block.id,
                "content": f"Unknown tool: {block.name}", "is_error": True
            })
            continue
        try:
            result = await coro
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": json.dumps(result)})
        except Exception as e:
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": str(e), "is_error": True})
    return results

# Usage in async agent loop
