from enum import Enum

class PermissionLevel(Enum):
    READ  = "read"
    WRITE = "write"
    ADMIN = "admin"

# Define which permission level each tool requires
TOOL_PERMISSIONS = {
    "search_documents":    PermissionLevel.READ,
    "get_user_profile":    PermissionLevel.READ,
    "create_ticket":       PermissionLevel.WRITE,
    "send_email":          PermissionLevel.WRITE,
    "delete_user":         PermissionLevel.ADMIN,
    "run_sql":             PermissionLevel.ADMIN,
}

def execute_tool_with_permission(block, user_permission: PermissionLevel) -> dict:
    required = TOOL_PERMISSIONS.get(block.name)
    if required is None:
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": f"Unknown tool: {block.name}", "is_error": True}

    perm_order = [PermissionLevel.READ, PermissionLevel.WRITE, PermissionLevel.ADMIN]
    if perm_order.index(user_permission) < perm_order.index(required):
        return {
            "type": "tool_result", "tool_use_id": block.id,
            "content": f"Permission denied: {block.name} requires {required.value}",
            "is_error": True
        }
    return execute_tool(block)

import hashlib, json, time

# Track recently executed write operations to prevent double-execution
_executed: dict[str, tuple[float, dict]] = {}  # key -> (timestamp, result)
IDEMPOTENCY_WINDOW = 30.0  # seconds

WRITE_TOOLS = {"create_ticket", "send_email", "place_order", "delete_file"}

def idempotent_execute(block) -> dict:
    """Prevent the same write tool from executing twice within the window."""
    if block.name not in WRITE_TOOLS:
        return execute_tool(block)  # read-only: no dedup needed

    key = hashlib.sha256(
        f"{block.name}:{json.dumps(block.input, sort_keys=True)}".encode()
    ).hexdigest()

    now = time.monotonic()
    entry = _executed.get(key)
    if entry and (now - entry[0]) < IDEMPOTENCY_WINDOW:
        # Return the cached result — do not re-execute
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": json.dumps({**entry[1], "_cached": True})}

    result_block = execute_tool(block)
    if not result_block.get("is_error"):
        _executed[key] = (now, json.loads(result_block["content"]))
    return result_block

# Dry-run mode: execute read-only tools but simulate write tools
DRY_RUN = True

def execute_tool_dry_run(block) -> dict:
    if not DRY_RUN or block.name not in WRITE_TOOLS:
        return execute_tool(block)

    # Simulate the write: return a plausible-looking result without side effects
    simulated = {
        "simulated": True,
        "tool": block.name,
        "input": block.input,
        "note": "Dry-run mode — no actual changes made."
    }
    return {"type": "tool_result", "tool_use_id": block.id, "content": json.dumps(simulated)}

from typing import Callable, Any
from dataclasses import dataclass

@dataclass
class ToolExecutionContext:
    tool_name: str
    tool_input: dict
    turn: int

PreHook  = Callable[[ToolExecutionContext], None]           # runs before execution
PostHook = Callable[[ToolExecutionContext, Any, bool], None]  # runs after; args: ctx, result, is_error

class HookedExecutor:
    def __init__(self, registry: dict, pre_hooks: list[PreHook] = None,
                 post_hooks: list[PostHook] = None):
        self.registry   = registry
        self.pre_hooks  = pre_hooks  or []
        self.post_hooks = post_hooks or []

    def run(self, block, turn: int = 0) -> dict:
        ctx = ToolExecutionContext(block.name, block.input, turn)

        for hook in self.pre_hooks:
            hook(ctx)           # e.g. rate-limit check, audit log

        fn = self.registry.get(block.name)
        if fn is None:
            result = None
            is_error = True
            content = f"Unknown tool: {block.name}"
        else:
            try:
                result  = fn(**block.input)
                content = json.dumps(result)
                is_error = False
            except Exception as e:
                result   = None
                content  = str(e)
                is_error = True

        for hook in self.post_hooks:
            hook(ctx, result, is_error)  # e.g. metrics, notifications

        return {"type": "tool_result", "tool_use_id": block.id,
                "content": content, "is_error": is_error}

# Example hooks
def audit_pre_hook(ctx: ToolExecutionContext) -> None:
    audit_log.write(f"TOOL_CALL tool={ctx.tool_name} input={json.dumps(ctx.input)}")

def metrics_post_hook(ctx: ToolExecutionContext, result, is_error: bool) -> None:
    metrics.increment("tool_calls_total", tags={"tool": ctx.tool_name, "error": str(is_error)})

executor = HookedExecutor(TOOL_REGISTRY, pre_hooks=[audit_pre_hook], post_hooks=[metrics_post_hook])

from dataclasses import dataclass, field

@dataclass
class ToolBudget:
    """Limit the number of times specific tools can be called per agent run."""
    limits: dict[str, int]
    _counts: dict[str, int] = field(default_factory=dict)

    def check(self, tool_name: str) -> str | None:
        """Returns an error message if the budget is exceeded, else None."""
        limit = self.limits.get(tool_name)
        if limit is None:
            return None  # no limit for this tool
        count = self._counts.get(tool_name, 0)
        if count >= limit:
            return f"Tool {tool_name!r} has reached its call limit ({limit}) for this run."
        return None

    def record(self, tool_name: str) -> None:
        self._counts[tool_name] = self._counts.get(tool_name, 0) + 1

budget = ToolBudget(limits={
    "send_email":  1,     # can only send one email per run
    "place_order": 1,     # safety: one order per turn
    "web_search":  10,    # prevent excessive search loops
})

def execute_with_budget(block, budget: ToolBudget) -> dict:
    error = budget.check(block.name)
    if error:
        return {"type": "tool_result", "tool_use_id": block.id,
                "content": error, "is_error": True}
    budget.record(block.name)
    return execute_tool(block)

import subprocess, json, tempfile, os

def run_python_sandboxed(code: str, timeout: int = 5) -> dict:
    """Execute model-generated Python in an isolated subprocess."""
    with tempfile.NamedTemporaryFile(mode="w", suffix=".py", delete=False) as f:
        f.write(code)
        script_path = f.name

    try:
        result = subprocess.run(
            ["python3", "-c",
             # Restricted exec: no network, no file writes outside /tmp
             f"import resource; resource.setrlimit(resource.RLIMIT_NOFILE, (10, 10)); exec(open({script_path!r}).read())"],
            capture_output=True, text=True, timeout=timeout
        )
        return {
            "stdout": result.stdout[:2000],
            "stderr": result.stderr[:500],
            "exit_code": result.returncode
        }
    except subprocess.TimeoutExpired:
        return {"error": "timeout", "exit_code": -1}
    finally:
        os.unlink(script_path)
